use CGI qw(:standard);
use DBI;
use Digest::MD5 qw(md5_hex);
use Crypt::Random qw(uran);
use POSIX qw(strftime);

my $cgi = CGI->new();
my $dbh = DBI->connect("dbi:SQLite:dbname=legacy_auth.db", "", "", { RaiseError => 1, AutoCommit => 1 });

sub generate_secure_salt {
    my $salt = "";
    for (1..16) {
        $salt .= sprintf("%02x", uran(0, 255));
    }
    return $salt;
}

sub hash_password_with_salt {
    my ($password, $salt) = @_;
    return md5_hex($password . $salt);
}

sub store_user {
    my ($username, $password) = @_;
    my $salt = generate_secure_salt();
    my $hashed_password = hash_password_with_salt($password, $salt);
    
    my $sth = $dbh->prepare("INSERT INTO users (username, password_hash, salt, created_at) VALUES (?, ?, ?, ?)");
    $sth->execute($username, $hashed_password, $salt, strftime("%Y-%m-%d %H:%M:%S", localtime));
}

sub authenticate_user {
    my ($username, $password) = @_;
    my $sth = $dbh->prepare("SELECT password_hash, salt FROM users WHERE username = ?");
    $sth->execute($username);
    my $row = $sth->fetchrow_hashref();
    
    return 0 unless $row;
    
    my $hashed_password = hash_password_with_salt($password, $row->{salt});
    return $hashed_password eq $row->{password_hash} ? 1 : 0;
}

